"use client"

import {
  useEffect,
  useState
} from "react"

export default function UserDashboard() {
  const [slot, setSlot] =
    useState<any>(null)

  useEffect(() => {
    fetch(
      "/api/user-parking"
    )
      .then((r) => r.json())
      .then(setSlot)
  }, [])

  return (
    <div className="p-8">
      <h1 className="text-3xl font-bold">
        User Dashboard
      </h1>

      {!slot && (
        <p className="mt-4">
          No vehicle found.
        </p>
      )}

      {slot && (
        <div className="mt-6 space-y-2">
          <p>
            <b>Slot:</b>
            {" "}
            {slot.slotId}
          </p>

          <p>
            <b>Vehicle:</b>
            {" "}
            {slot.licensePlate}
          </p>

          <p>
            <b>Status:</b>
            {" "}
            {slot.status}
          </p>

          <p>
            <b>Current Bill:</b>
            {" "}
            ₹{slot.bill}
          </p>
        </div>
      )}
    </div>
  )
}